+            let _det = is_likely_markdown(MARKDOWN_PROFILE_CONTENT);
+        }
+        let elapsed = start.elapsed();
+        let per_call_us = elapsed.as_micros() / 1000;
+        assert!(
+            per_call_us < 100,
